    def drop(self, *symbols):
        """Drop generators from this domain. """
        symset = set(symbols)
        newsyms = tuple(s for s in self.symbols if s not in symset)
        domain = self.domain.drop(*symbols)
        if not newsyms:
            return domain
        else:
            return self.__class__(domain, newsyms, self.order)

